import React, { useState, useRef, useCallback } from "react";
import { parseProgrammeHTML } from "./utils/parserProgramme";
import { useLogs } from "./hooks/useLogs";
import { useWeight } from "./hooks/useWeight";
import { ExerciseCard } from "./components/ExerciseCard";
import { WeightTracker } from "./components/WeightChart";
import { LOGO_B64 } from "./utils/logo";
import "./App.css";

const GREEN = "#22c55e";

/* ── Nav icons ── */
const IconDumbbell = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
    <path d="M6.5 6.5h1v11h-1zM16.5 6.5h1v11h-1z"/>
    <line x1="3" y1="9" x2="3" y2="15"/><line x1="2" y1="9" x2="4" y2="9"/><line x1="2" y1="15" x2="4" y2="15"/>
    <line x1="21" y1="9" x2="21" y2="15"/><line x1="20" y1="9" x2="22" y2="9"/><line x1="20" y1="15" x2="22" y2="15"/>
    <line x1="7.5" y1="12" x2="16.5" y2="12"/>
  </svg>
);
const IconScale = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
    <circle cx="12" cy="12" r="9"/>
    <path d="M12 7v5l3 3"/>
    <line x1="7" y1="3.34" x2="7" y2="5"/><line x1="17" y1="3.34" x2="17" y2="5"/>
  </svg>
);
const IconScale2 = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round">
    <rect x="3" y="15" width="18" height="5" rx="2"/>
    <path d="M12 15V9"/>
    <path d="M8 9h8"/>
    <path d="M6 9c0-3.31 2.69-6 6-6s6 2.69 6 6"/>
    <line x1="9" y1="12" x2="9" y2="9"/><line x1="15" y1="12" x2="15" y2="9"/>
  </svg>
);

/* ── Session tab ── */
function SessionTab({ session, active, onClick, weekIdx, sessionIdx, getHistory, programme }) {
  let total = 0, done = 0;
  if (programme) {
    const s = programme.weeks[weekIdx]?.sessions[sessionIdx];
    if (s) s.exercises.forEach((ex, ei) => { total++; if (getHistory(weekIdx, sessionIdx, ei).length > 0) done++; });
  }
  const pct = total > 0 ? Math.round((done / total) * 100) : 0;
  return (
    <button className={`session-tab ${active ? "active" : ""}`} onClick={onClick}>
      <span>{session.name || `Séance ${sessionIdx + 1}`}</span>
      {total > 0 && <span className="session-tab-pct" style={{ color: pct === 100 ? GREEN : undefined }}>{pct}%</span>}
    </button>
  );
}

/* ── Import screen ── */
function ImportScreen({ onImport, isDragging }) {
  const inputRef = useRef();
  return (
    <div className="import-screen">
      <div className={`import-drop-zone ${isDragging ? "dragging" : ""}`} onClick={() => inputRef.current?.click()}>
        <input ref={inputRef} type="file" accept=".html" onChange={onImport} style={{ display: "none" }} />
        <div className="import-icon">
          <svg viewBox="0 0 48 48" fill="none">
            <rect x="6" y="4" width="26" height="34" rx="3" stroke="#22c55e" strokeWidth="1.8"/>
            <path d="M32 4l8 8" stroke="#22c55e" strokeWidth="1.8" strokeLinecap="round"/>
            <rect x="32" y="4" width="8" height="8" rx="1" stroke="#22c55e" strokeWidth="1.8"/>
            <line x1="14" y1="16" x2="28" y2="16" stroke="#22c55e" strokeWidth="1.5" strokeLinecap="round" opacity="0.4"/>
            <line x1="14" y1="22" x2="28" y2="22" stroke="#22c55e" strokeWidth="1.5" strokeLinecap="round" opacity="0.4"/>
            <line x1="14" y1="28" x2="22" y2="28" stroke="#22c55e" strokeWidth="1.5" strokeLinecap="round" opacity="0.4"/>
          </svg>
        </div>
        <div className="import-title">Importer un programme</div>
        <div className="import-sub">Fichier .html exporté depuis le builder RB Performance</div>
        <div className="import-cta">Choisir un fichier</div>
      </div>
    </div>
  );
}

/* ── App ── */
export default function App() {
  const [programme, setProgramme] = useState(null);
  const [activeWeek, setActiveWeek] = useState(0);
  const [activeSession, setActiveSession] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const [page, setPage] = useState("training"); // "training" | "weight"

  const { getHistory, getLatest, saveLog, getDelta } = useLogs(programme?.name);
  const { entries, addEntry, removeEntry, getStats } = useWeight();

  const handleImport = useCallback(async (e) => {
    const file = e.target?.files?.[0] || e.dataTransfer?.files?.[0];
    if (!file) return;
    const text = await file.text();
    const parsed = parseProgrammeHTML(text);
    setProgramme(parsed);
    setActiveWeek(0);
    setActiveSession(0);
    setPage("training");
  }, []);

  const handleDragOver = (e) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = () => setIsDragging(false);
  const handleDrop = (e) => { e.preventDefault(); setIsDragging(false); handleImport(e); };

  const currentWeek = programme?.weeks[activeWeek];
  const sessions = currentWeek?.sessions || [];
  const safeSessionIdx = Math.min(activeSession, Math.max(0, sessions.length - 1));
  const session = sessions[safeSessionIdx];

  let totalEx = 0, doneEx = 0;
  if (programme) {
    programme.weeks.forEach((w, wi) => {
      w.sessions.forEach((s, si) => {
        s.exercises.forEach((ex, ei) => { totalEx++; if (getHistory(wi, si, ei).length > 0) doneEx++; });
      });
    });
  }
  const globalPct = totalEx > 0 ? Math.round((doneEx / totalEx) * 100) : 0;
  const weightStats = getStats();

  return (
    <div className="app-root" onDragOver={handleDragOver} onDragLeave={handleDragLeave} onDrop={handleDrop}>

      {/* ── Topbar ── */}
      <header className="topbar">
        <div className="topbar-brand">
          <div className="topbar-logo-img">
            <img src={LOGO_B64} alt="RB Performance" />
          </div>
          <span className="topbar-name">RB&nbsp;<span>Performance</span></span>
        </div>
        <div className="topbar-right">
          {programme && (
            <label className="topbar-import-btn">
              <input type="file" accept=".html" onChange={handleImport} style={{ display: "none" }} />
              <svg viewBox="0 0 20 20" fill="none">
                <path d="M10 3v10M5 8l5-5 5 5" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
                <path d="M3 15h14" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"/>
              </svg>
              Changer
            </label>
          )}
        </div>
      </header>

      {/* ── Content ── */}
      {page === "training" && !programme ? (
        <ImportScreen onImport={handleImport} isDragging={isDragging} />
      ) : page === "training" ? (
        <main className="main">
          {/* Programme header */}
          <div className="prog-header">
            <div>
              <div className="prog-eyebrow">Programme actif</div>
              <h1 className="prog-name">{programme.name}</h1>
              {programme.clientName && <div className="prog-client">{programme.clientName}</div>}
              <div className="prog-meta">
                <span>{programme.weeks.length} semaine{programme.weeks.length > 1 ? "s" : ""}</span>
                <span className="dot">·</span>
                <span>{programme.weeks.reduce((a, w) => a + w.sessions.length, 0)} séances</span>
                <span className="dot">·</span>
                <span>{totalEx} exercices</span>
              </div>
            </div>
            {/* Ring */}
            <div className="prog-ring-wrap">
              <svg className="prog-ring" viewBox="0 0 50 50">
                <circle cx="25" cy="25" r="20" fill="none" stroke="#1a1a1a" strokeWidth="4"/>
                <circle
                  cx="25" cy="25" r="20" fill="none" stroke={GREEN} strokeWidth="4"
                  strokeLinecap="round"
                  strokeDasharray={`${2 * Math.PI * 20}`}
                  strokeDashoffset={`${2 * Math.PI * 20 * (1 - globalPct / 100)}`}
                  transform="rotate(-90 25 25)"
                  style={{ transition: "stroke-dashoffset 0.8s ease" }}
                />
              </svg>
              <span className="prog-ring-pct">{globalPct}%</span>
            </div>
          </div>

          {/* Weeks */}
          <div className="week-nav">
            {programme.weeks.map((w, i) => (
              <button key={i} className={`week-btn ${activeWeek === i ? "active" : ""}`}
                onClick={() => { setActiveWeek(i); setActiveSession(0); }}>
                S{i + 1}
              </button>
            ))}
          </div>

          {/* Sessions */}
          {sessions.length > 1 && (
            <div className="session-tabs">
              {sessions.map((s, j) => (
                <SessionTab key={j} session={s} active={safeSessionIdx === j}
                  onClick={() => setActiveSession(j)}
                  weekIdx={activeWeek} sessionIdx={j}
                  getHistory={getHistory} programme={programme} />
              ))}
            </div>
          )}

          {session && (
            <div className="session-content">
              <div className="session-header">
                <div>
                  <div className="session-eyebrow">Semaine {activeWeek + 1} · Séance {safeSessionIdx + 1}</div>
                  <h2 className="session-name">{session.name}</h2>
                  {session.description && <p className="session-desc">{session.description}</p>}
                </div>
                <div className="session-count">{session.exercises.length}<span>ex</span></div>
              </div>

              <div className="exercises-list">
                {session.exercises.map((ex, k) => (
                  <ExerciseCard key={k} ex={ex}
                    weekIdx={activeWeek} sessionIdx={safeSessionIdx} exIdx={k} globalIndex={k}
                    getHistory={getHistory} getLatest={getLatest} saveLog={saveLog} getDelta={getDelta} />
                ))}
              </div>

              {session.finisher && (
                <div className="finisher-block">
                  <div className="finisher-label">⚡ Finisher</div>
                  <div className="finisher-text">{session.finisher}</div>
                </div>
              )}
            </div>
          )}
        </main>
      ) : (
        /* Weight page */
        <main className="main" style={{ paddingTop: 8 }}>
          <WeightTracker entries={entries} addEntry={addEntry} removeEntry={removeEntry} getStats={getStats} />
        </main>
      )}

      {/* ── Bottom Nav ── */}
      <nav className="bottom-nav">
        <button className={`nav-tab ${page === "training" ? "active" : ""}`} onClick={() => setPage("training")}>
          <IconDumbbell />
          Entraînement
        </button>
        <button className={`nav-tab ${page === "weight" ? "active" : ""}`} onClick={() => setPage("weight")}>
          <IconScale2 />
          Poids
          {weightStats && (
            <span style={{
              position: "absolute", top: 6, right: "calc(50% - 18px)",
              width: 6, height: 6, borderRadius: "50%", background: GREEN
            }} />
          )}
        </button>
      </nav>
    </div>
  );
}
